html:
{% set s = frappe.get_single("Dealership Settings") %}

<div style="
    width: 100%;
    border-bottom: 3px solid #1a3c6e;
    padding-bottom: 16px;
    margin-bottom: 20px;
    font-family: Arial, sans-serif;
">

    <!-- Row: Logo + Dealership Info LEFT | Invoice Title + Meta RIGHT -->
    <div style="display: flex; justify-content: space-between; align-items: flex-start;">

        <!-- LEFT: Logo and dealership details -->
        <div style="display: flex; align-items: flex-start; gap: 14px;">

            {% if s.logo %}
            <img src="{{ s.logo }}"
                 style="max-height: 70px; max-width: 120px; object-fit: contain;">
            {% endif %}

            <div>
                <div style="
                    font-size: 20px;
                    font-weight: bold;
                    color: #1a3c6e;
                    margin-bottom: 4px;
                ">{{ s.dealership_name }}</div>

                <div style="font-size: 11px; color: #555; line-height: 1.6;">
                    {{ s.address }}<br>
                    {{ s.from_email }}
                </div>
            </div>
        </div>

        <!-- RIGHT: Invoice label + document meta -->
        <div style="text-align: right;">

            <div style="
                font-size: 22px;
                font-weight: bold;
                color: #1a3c6e;
                letter-spacing: 1px;
                margin-bottom: 8px;
            ">SALE INVOICE</div>

            <table style="
                font-size: 12px;
                border-collapse: collapse;
                margin-left: auto;
            ">
                <tr>
                    <td style="padding: 3px 10px 3px 0; color: #777;">Invoice No.</td>
                    <td style="padding: 3px 0; font-weight: bold; color: #222;">{{ doc.name }}</td>
                </tr>
                <tr>
                    <td style="padding: 3px 10px 3px 0; color: #777;">Sale Date</td>
                    <td style="padding: 3px 0; font-weight: bold; color: #222;">{{ doc.sale_date }}</td>
                </tr>
                <tr>
                    <td style="padding: 3px 10px 3px 0; color: #777;">Payment Mode</td>
                    <td style="padding: 3px 0; font-weight: bold; color: #222;">{{ doc.payment_mode }}</td>
                </tr>
                <tr>
                    <td style="padding: 3px 10px 3px 0; color: #777;">Status</td>
                    <td style="padding: 3px 0;">
                        <span style="
                            background: #1a3c6e;
                            color: white;
                            padding: 2px 10px;
                            border-radius: 10px;
                            font-size: 11px;
                        ">{{ doc.status }}</span>
                    </td>
                </tr>
            </table>
        </div>

    </div>

    <!-- Divider line under header -->
    <div style="
        margin-top: 14px;
        height: 2px;
        background: linear-gradient(to right, #1a3c6e, #4a7ab0, #e8eef7);
    "></div>

    <!-- Customer + Sales Consultant row -->
    <div style="
        display: flex;
        justify-content: space-between;
        margin-top: 14px;
        gap: 20px;
    ">

        <!-- Customer Details -->
        <div style="
            flex: 1;
            background: #f4f7fc;
            border-left: 4px solid #1a3c6e;
            padding: 10px 14px;
            border-radius: 0 6px 6px 0;
        ">
            <div style="
                font-size: 10px;
                font-weight: bold;
                color: #1a3c6e;
                text-transform: uppercase;
                letter-spacing: 0.5px;
                margin-bottom: 6px;
            ">Bill To</div>

            <div style="font-size: 13px; font-weight: bold; color: #222; margin-bottom: 2px;">
                {{ doc.customer_name }}
            </div>
            <div style="font-size: 11px; color: #555; line-height: 1.7;">
                {% if doc.customer_phone %}
                Ph: {{ doc.customer_phone }}<br>
                {% endif %}
                {% if doc.customer_email %}
                Email: {{ doc.customer_email }}
                {% endif %}
            </div>
        </div>

        <!-- Sales Consultant Details -->
        <div style="
            flex: 1;
            background: #f4f7fc;
            border-left: 4px solid #4a7ab0;
            padding: 10px 14px;
            border-radius: 0 6px 6px 0;
        ">
            <div style="
                font-size: 10px;
                font-weight: bold;
                color: #4a7ab0;
                text-transform: uppercase;
                letter-spacing: 0.5px;
                margin-bottom: 6px;
            ">Sales Consultant</div>

            <div style="font-size: 13px; font-weight: bold; color: #222; margin-bottom: 2px;">
                {{ doc.sales_consultant }}
            </div>
            {% if doc.referrer_name %}
            <div style="font-size: 11px; color: #555;">
                Referral by: {{ doc.referrer_name }}
            </div>
            {% endif %}
        </div>

    </div>

</div>
